   158→static void badend(void)
   159→{
   160→	fprintf(stderr, "%s: line %" Z "d: unexpected end of input\n",
   161→		prog, lineno);
   162→}
   163→
   164→static int unhex(unsigned char *c2)
   165→{
   166→	int x, c;
   167→	x = *c2++ & 0x4f;
   168→	if (x & 0x40)
   169→		x -= 55;
   170→	c = x << 4;
   171→	x = *c2 & 0x4f;
   172→	if (x & 0x40)
   173→		x -= 55;
   174→	c |= x;
   175→	return c;
   176→}
   177→
   178→static int readline(MDB_val *out, MDB_val *buf)
   179→{
   180→	unsigned char *c1, *c2, *end;
   181→	size_t len, l2;
   182→	int c;
   183→
   184→	if (!(mode & NOHDR)) {
   185→		c = fgetc(stdin);
   186→		if (c == EOF) {
   187→			Eof = 1;
   188→			return EOF;
   189→		}
   190→		if (c != ' ') {
   191→			lineno++;
   192→			if (fgets(buf->mv_data, buf->mv_size, stdin) == NULL) {
   193→badend:
   194→				Eof = 1;
   195→				badend();
   196→				return EOF;
   197→			}
   198→			if (c == 'D' && !strncmp(buf->mv_data, "ATA=END", STRLENOF("ATA=END")))
   199→				return EOF;
   200→			goto badend;
   201→		}
   202→	}
   203→	if (fgets(buf->mv_data, buf->mv_size, stdin) == NULL) {
   204→		Eof = 1;
   205→		return EOF;
   206→	}
   207→	lineno++;
   208→
   209→	c1 = buf->mv_data;
   210→	len = strlen((char *)c1);
   211→	l2 = len;
   212→
   213→	/* Is buffer too short? */
   214→	while (c1[len-1] != '\n') {
   215→		buf->mv_data = realloc(buf->mv_data, buf->mv_size*2);
   216→		if (!buf->mv_data) {
   217→			Eof = 1;
   218→			fprintf(stderr, "%s: line %" Z "d: out of memory, line too long\n",
   219→				prog, lineno);
   220→			return EOF;
   221→		}
   222→		c1 = buf->mv_data;
   223→		c1 += l2;
   224→		if (fgets((char *)c1, buf->mv_size+1, stdin) == NULL) {
   225→			Eof = 1;
   226→			badend();
   227→			return EOF;
   228→		}
   229→		buf->mv_size *= 2;
   230→		len = strlen((char *)c1);
   231→		l2 += len;
   232→	}
   233→	c1 = c2 = buf->mv_data;
   234→	len = l2;
   235→	c1[--len] = '\0';
   236→	end = c1 + len;
   237→
   238→	if (mode & PRINT) {
   239→		while (c2 < end) {
   240→			if (*c2 == '\\') {
   241→				if (c2[1] == '\\') {
   242→					*c1++ = *c2;
   243→				} else {
   244→					if (c2+3 > end || !isxdigit(c2[1]) || !isxdigit(c2[2])) {
   245→						Eof = 1;
   246→						badend();
   247→						return EOF;
   248→					}
   249→					*c1++ = unhex(++c2);
   250→				}
   251→				c2 += 2;
   252→			} else {
   253→				/* copies are redundant when no escapes were used */
   254→				*c1++ = *c2++;
   255→			}
   256→		}
   257→	} else {
   258→		/* odd length not allowed */
   259→		if (len & 1) {
   260→			Eof = 1;
   261→			badend();
   262→			return EOF;
   263→		}
   264→		while (c2 < end) {
   265→			if (!isxdigit(*c2) || !isxdigit(c2[1])) {
   266→				Eof = 1;
   267→				badend();
   268→				return EOF;
   269→			}
   270→			*c1++ = unhex(c2);
   271→			c2 += 2;
   272→		}
   273→	}
   274→	c2 = out->mv_data = buf->mv_data;
   275→	out->mv_size = c1 - c2;
   276→
   277→	return 0;
   278→}
