   280→static void usage(void)
   281→{
   282→	fprintf(stderr, "usage: %s [-V] [-a] [-f input] [-n] [-s name] [-N] [-T] dbpath\n", prog);
   283→	exit(EXIT_FAILURE);
   284→}
